464	  if (sectionStart < 0) return null;
465	  const section = compact.slice(sectionStart, sectionStart + 20000);
466	
467	  const matches = [...section.matchAll(/>(\d{1,2}\.\d{2,4})</g)];
468	  const candidates = matches
469	    .map((m) => Number(m[1]))
470	    .filter((n) => Number.isFinite(n) && n > 0 && n < 5);
