type CoinGeckoMarketChart = {
  prices: Array<[number, number]>;
};

type BinanceTicker = {
  price?: string;
};

async function fetchBtcPrice(): Promise<number | null> {
  const ticker = await fetchJson<BinanceTicker>(
    'https://api.binance.com/api/v3/ticker/price?symbol=BTCUSDT'
  );
  if (ticker?.price) {
    const p = Number(ticker.price);
    if (Number.isFinite(p)) return p;
  }
  const cfg = coingeckoConfig();
  const data = await fetchJson<{ bitcoin?: { usd?: number } }>(
    `${cfg.base}/simple/price?ids=bitcoin&vs_currencies=usd`,
    { headers: cfg.headers }
  );
  return data?.bitcoin?.usd ?? null;
}

async function fetchAltBtcData(
  coinId: string
): Promise<{
  currentRatio: number | null;
  currentCyclePeak: number | null;
  fiveYearLow: number | null;
}> {
  const cfg = coingeckoConfig();

  // Fetch current price in BTC
  const priceData = await fetchJson<Record<string, { btc?: number }>>(
    `${cfg.base}/simple/price?ids=${coinId}&vs_currencies=btc`,
    { headers: cfg.headers }
  );
  const currentRatio = priceData?.[coinId]?.btc ?? null;

  // Fetch 5 year history for ALT/BTC
  const chart = await fetchJson<CoinGeckoMarketChart>(
    `${cfg.base}/coins/${coinId}/market_chart?vs_currency=btc&days=1825&interval=daily`,
    { headers: cfg.headers }
  );

  let currentCyclePeak: number | null = null;
  let fiveYearLow: number | null = null;

  if (chart?.prices?.length) {
    const values = chart.prices.map((p) => p[1]).filter((v) => v > 0);
    if (values.length) {
      fiveYearLow = Math.min(...values);
      // Current cycle: last ~2 years (730 days)
      const cyclePrices = values.slice(-730);
      currentCyclePeak = Math.max(...cyclePrices);
    }
  }

  return { currentRatio, currentCyclePeak, fiveYearLow };
}

// PLACEHOLDER_GRADING

