function computeGrade(
  cycleChange: number | null,
  aboveFiveYearLow: number | null,
  isVeteran: boolean
): { grade: Grade; action: Action; observation: string } {
  // Single-cycle coins: only Filter 2
  if (!isVeteran) {
    if (aboveFiveYearLow === null) {
      return { grade: 'B', action: '观望', observation: '数据不足，无法完成完整评估。仅有部分历史数据可参考。' };
    }
    if (aboveFiveYearLow > 25) {
      return { grade: 'A', action: '关注', observation: `单周期新币，距离5年低点 ${aboveFiveYearLow.toFixed(1)}%，处于健康反弹区。无上轮周期数据可对比，需持续观察其 BTC 汇率走势。` };
    }
    return { grade: 'F', action: '永久避开', observation: `单周期新币，距离5年低点仅 ${aboveFiveYearLow.toFixed(1)}%，处于历史最差水平。振荡器机制尚未验证，风险极高。` };
  }

  // Veteran coins: Filter 1 + Filter 2
  if (cycleChange !== null && cycleChange > 0) {
    return { grade: 'S', action: '关注', observation: `汇率超越上轮高点 ${cycleChange.toFixed(1)}%，跑赢 BTC。这是极少数能在周期间持续增值的资产，振荡器机制强劲。` };
  }

  if (cycleChange !== null && cycleChange < -65) {
    return { grade: 'F', action: '永久避开', observation: `汇率较上轮高点暴跌 ${cycleChange.toFixed(1)}%，振荡器机制已失效。这类资产在每个周期都会进一步稀释持有者价值。` };
  }

  if (cycleChange !== null && cycleChange >= -35) {
    if (aboveFiveYearLow !== null && aboveFiveYearLow > 25) {
      return { grade: 'A', action: '关注', observation: `汇率跌幅 ${cycleChange.toFixed(1)}% 在可控范围内，且距离5年低点 ${aboveFiveYearLow.toFixed(1)}%，处于健康反弹区。适合波段交易。` };
    }
    return { grade: 'B', action: '观望', observation: `汇率跌幅 ${cycleChange.toFixed(1)}% 尚可，但距离5年低点过近（${aboveFiveYearLow?.toFixed(1) ?? 'N/A'}%），反弹动能存疑。` };
  }

  // -35% to -65%
  return { grade: 'B', action: '观望', observation: `汇率跌幅 ${cycleChange?.toFixed(1) ?? 'N/A'}%，处于 -35% 到 -65% 的弱振荡区间。反弹动能正在衰减，需要更多确认信号。` };
}

export async function getOscillatorData(): Promise<OscillatorData> {
  const btcPrice = await fetchBtcPrice();

  // Fetch all coins in parallel, with rate limiting consideration
  // CoinGecko free tier: 10-30 req/min, so we batch
  const batchSize = 5;
  const results: OscillatorResult[] = [];

  for (let i = 0; i < OSCILLATOR_COINS.length; i += batchSize) {
    const batch = OSCILLATOR_COINS.slice(i, i + batchSize);
    const batchResults = await Promise.all(
      batch.map(async (coin) => {
        const data = await fetchAltBtcData(coin.id);
        const lastCyclePeak = coin.lastCyclePeak ?? null;
        const isVeteran = coin.category === 'veteran';

        let cycleChange: number | null = null;
        if (isVeteran && data.currentCyclePeak !== null && lastCyclePeak !== null && lastCyclePeak > 0) {
          cycleChange = ((data.currentCyclePeak - lastCyclePeak) / lastCyclePeak) * 100;
        }

        let aboveFiveYearLow: number | null = null;
        if (data.currentRatio !== null && data.fiveYearLow !== null && data.fiveYearLow > 0) {
          aboveFiveYearLow = ((data.currentRatio - data.fiveYearLow) / data.fiveYearLow) * 100;
        }

        const { grade, action, observation } = computeGrade(cycleChange, aboveFiveYearLow, isVeteran);

        return {
          coin,
          currentRatio: data.currentRatio,
          currentCyclePeak: data.currentCyclePeak,
          lastCyclePeak,
          fiveYearLow: data.fiveYearLow,
          cycleChange,
          aboveFiveYearLow,
          grade,
          action,
          observation,
        } satisfies OscillatorResult;
      })
    );
    results.push(...batchResults);
  }

  // Sort: S first, then A, B, F
  const gradeOrder: Record<Grade, number> = { S: 0, A: 1, B: 2, F: 3 };
  results.sort((a, b) => gradeOrder[a.grade] - gradeOrder[b.grade]);

  return {
    generatedAt: new Date().toISOString(),
    results,
    btcPrice,
  };
}

