type FilterTab = 'all' | 'S' | 'A' | 'B' | 'F';

function GradeSummary({ results }: { results: OscillatorResult[] }) {
  const counts = { S: 0, A: 0, B: 0, F: 0 };
  for (const r of results) counts[r.grade]++;

  return (
    <div className='grid grid-cols-4 gap-3'>
      {(Object.entries(counts) as [Grade, number][]).map(([grade, count]) => {
        const style = GRADE_STYLES[grade];
        return (
          <div key={grade} className={`rounded-lg border p-3 ${style.bg} ${style.border}`}>
            <div className='flex items-center justify-between'>
              <span className={`text-2xl font-bold ${style.text}`}>{count}</span>
              <span className={`text-xs font-semibold ${style.text}`}>{grade}</span>
            </div>
            <p className={`text-[10px] mt-1 ${style.text} opacity-80`}>{style.label}</p>
          </div>
        );
      })}
    </div>
  );
}

export default function OscillatorClient({ data }: { data: OscillatorData }) {
  const [filter, setFilter] = useState<FilterTab>('all');
  const [categoryFilter, setCategoryFilter] = useState<'all' | 'veteran' | 'single-cycle'>('all');

  const filtered = data.results.filter((r) => {
    if (filter !== 'all' && r.grade !== filter) return false;
    if (categoryFilter !== 'all' && r.coin.category !== categoryFilter) return false;
    return true;
  });

  return (
    <section className='space-y-8 pb-8'>
      <div className='space-y-3'>
        <h1 className='font-medium text-2xl tracking-tighter'>oscillator</h1>
        <p className='text-sm text-muted-foreground'>
          Altcoin Strength Monitor — 基于振荡器理论（Oscillator Thesis）的山寨币实时强度监测。
          <span className='font-medium text-foreground'> 汇率才是资产强弱的真相，美元价只是幻象。</span>
        </p>
        <p className='text-xs text-muted-foreground'>
          BTC Price: {data.btcPrice ? `$${data.btcPrice.toLocaleString('en-US', { maximumFractionDigits: 2 })}` : 'N/A'}
          {' · '}
          Last refresh: {new Date(data.generatedAt).toLocaleString('en-US')}
        </p>
      </div>

      <GradeSummary results={data.results} />

      <div className='rounded-xl border p-4 space-y-3'>
        <h2 className='text-sm font-semibold'>Grading Methodology</h2>
        <div className='grid grid-cols-1 sm:grid-cols-2 gap-2 text-xs text-muted-foreground'>
          <div className='space-y-1'>
            <p className='font-medium text-foreground'>Filter 1: 汇率周期对比</p>
            <p>对比本周期汇率顶点与上一周期顶点</p>
            <p>· 正增长 → 跑赢 BTC（S级）</p>
            <p>· 跌幅 &gt; 65% → 振荡器失效（F级）</p>
          </div>
          <div className='space-y-1'>
            <p className='font-medium text-foreground'>Filter 2: 距离5年低点</p>
            <p>当前汇率距离5年历史最低的百分比</p>
            <p>· &gt; 25% → 健康反弹区</p>
            <p>· &lt; 25% → 历史最差水平，极度警惕</p>
          </div>
        </div>
      </div>

      <div className='flex flex-wrap gap-2'>
        {(['all', 'S', 'A', 'B', 'F'] as FilterTab[]).map((tab) => (
          <button
            key={tab}
            onClick={() => setFilter(tab)}
            className={`text-xs px-3 py-1.5 rounded-full border transition-colors ${
              filter === tab
                ? 'bg-foreground text-background border-foreground'
                : 'bg-background text-muted-foreground border-border hover:border-foreground/30'
            }`}
          >
            {tab === 'all' ? 'All' : `${tab} Grade`}
          </button>
        ))}
        <div className='w-px bg-border mx-1' />
        {(['all', 'veteran', 'single-cycle'] as const).map((cat) => (
          <button
            key={cat}
            onClick={() => setCategoryFilter(cat)}
            className={`text-xs px-3 py-1.5 rounded-full border transition-colors ${
              categoryFilter === cat
                ? 'bg-foreground text-background border-foreground'
                : 'bg-background text-muted-foreground border-border hover:border-foreground/30'
            }`}
          >
            {cat === 'all' ? 'All Types' : cat === 'veteran' ? 'Veteran' : 'Single-Cycle'}
          </button>
        ))}
      </div>

      <div className='space-y-3'>
        {filtered.length === 0 && (
          <p className='text-sm text-muted-foreground text-center py-8'>
            No coins match the current filter.
          </p>
        )}
        {filtered.map((result) => (
          <CoinCard key={result.coin.id} result={result} />
        ))}
      </div>

      <div className='pt-2 border-t text-xs text-muted-foreground space-y-1'>
        <p>Data Sources: CoinGecko (ALT/BTC ratios, historical data) · Binance (BTC price)</p>
        <p>DYOR — 本页面仅供观察参考，不构成任何投资建议。</p>
      </div>
    </section>
  );
}

