            <p>对比本周期汇率顶点与上一周期顶点</p>
            <p>· 正增长 → 跑赢 BTC（S级）</p>
            <p>· 跌幅 &gt; 65% → 振荡器失效（F级）</p>
          </div>
          <div className='space-y-1'>
            <p className='font-medium text-foreground'>Filter 2: 距离5年低点</p>
            <p>当前汇率距离5年历史最低的百分比</p>
            <p>· &gt; 25% → 健康反弹区</p>
            <p>· &lt; 25% → 历史最差水平，极度警惕</p>
          </div>
        </div>
      </div>

      <div className='flex flex-wrap gap-2'>
        {(['all', 'S', 'A', 'B', 'F'] as FilterTab[]).map((tab) => (
          <button
            key={tab}
            onClick={() => setFilter(tab)}
            className={`text-xs px-3 py-1.5 rounded-full border transition-colors ${
              filter === tab
                ? 'bg-foreground text-background border-foreground'
                : 'bg-background text-muted-foreground border-border hover:border-foreground/30'
            }`}
          >
            {tab === 'all' ? 'All' : `${tab} Grade`}
          </button>
        ))}
        <div className='w-px bg-border mx-1' />
        {(['all', 'veteran', 'single-cycle'] as const).map((cat) => (
          <button
            key={cat}
            onClick={() => setCategoryFilter(cat)}
            className={`text-xs px-3 py-1.5 rounded-full border transition-colors ${
              categoryFilter === cat
                ? 'bg-foreground text-background border-foreground'
                : 'bg-background text-muted-foreground border-border hover:border-foreground/30'
            }`}
          >
            {cat === 'all' ? 'All Types' : cat === 'veteran' ? 'Veteran' : 'Single-Cycle'}
          </button>
        ))}
      </div>

      <div className='space-y-3'>
        {filtered.length === 0 && (
          <p className='text-sm text-muted-foreground text-center py-8'>
            No coins match the current filter.
          </p>
        )}
        {filtered.map((result) => (
          <CoinCard key={result.coin.id} result={result} />
        ))}
      </div>

      <div className='pt-2 border-t text-xs text-muted-foreground space-y-1'>
        <p>Data Sources: CoinGecko (ALT/BTC ratios, historical data) · Binance (BTC price)</p>
        <p>DYOR — 本页面仅供观察参考，不构成任何投资建议。</p>
      </div>
    </section>
  );
}

toolUseResult.originalFile:
'use client';

import { useState } from 'react';
import type { OscillatorData, OscillatorResult, Grade } from '@/lib/oscillator-data';

const GRADE_STYLES: Record<Grade, { bg: string; text: string; border: string; label: string }> = {
  S: { bg: 'bg-emerald-500/15', text: 'text-emerald-600', border: 'border-emerald-500/30', label: 'Outperformed' },
  A: { bg: 'bg-blue-500/15', text: 'text-blue-600', border: 'border-blue-500/30', label: 'Strong Oscillator' },
  B: { bg: 'bg-amber-500/15', text: 'text-amber-600', border: 'border-amber-500/30', label: 'Weak Oscillator' },
  F: { bg: 'bg-red-500/15', text: 'text-red-600', border: 'border-red-500/30', label: 'Failed / Avoid' },
};

const ACTION_STYLES: Record<string, string> = {
  '关注': 'bg-emerald-500/15 text-emerald-600 border-emerald-500/30',
  '观望': 'bg-amber-500/15 text-amber-600 border-amber-500/30',
  '永久避开': 'bg-red-500/15 text-red-600 border-red-500/30',
};

function formatRatio(value: number | null): string {
  if (value === null) return 'N/A';
  if (value < 0.0001) return value.toExponential(4);
  return value.toFixed(6);
}

function formatPct(value: number | null): string {
  if (value === null) return 'N/A';
  const sign = value >= 0 ? '+' : '';
  return `${sign}${value.toFixed(1)}%`;
}

function CoinCard({ result }: { result: OscillatorResult }) {
  const style = GRADE_STYLES[result.grade];
  const actionStyle = ACTION_STYLES[result.action] ?? '';

  return (
    <div className='rounded-xl border p-4 bg-background/80 space-y-3'>
      <div className='flex items-center justify-between'>
        <div className='flex items-center gap-2'>
          <span className='text-sm font-semibold'>{result.coin.symbol}</span>
          <span className='text-xs text-muted-foreground'>{result.coin.name}</span>
          <span className={`text-[10px] px-1.5 py-0.5 rounded-full border ${
            result.coin.category === 'veteran'
              ? 'bg-violet-500/10 text-violet-600 border-violet-500/20'
              : 'bg-cyan-500/10 text-cyan-600 border-cyan-500/20'
          }`}>
            {result.coin.category === 'veteran' ? 'Veteran' : 'Single-Cycle'}
          </span>
        </div>
        <div className='flex items-center gap-2'>
          <span className={`text-xs font-bold px-2 py-1 rounded-full border ${style.bg} ${style.text} ${style.border}`}>
            {result.grade}
          </span>
          <span className={`text-[10px] px-2 py-0.5 rounded-full border ${actionStyle}`}>
            {result.action}
          </span>
        </div>
      </div>

      <div className='grid grid-cols-2 sm:grid-cols-4 gap-2'>
        <div className='rounded-lg border p-2 bg-background/60'>
          <p className='text-[10px] text-muted-foreground'>Current ALT/BTC</p>
          <p className='text-xs font-semibold'>{formatRatio(result.currentRatio)}</p>
        </div>
        <div className='rounded-lg border p-2 bg-background/60'>
          <p className='text-[10px] text-muted-foreground'>Cycle Peak</p>
          <p className='text-xs font-semibold'>{formatRatio(result.currentCyclePeak)}</p>
        </div>
        <div className='rounded-lg border p-2 bg-background/60'>
          <p className='text-[10px] text-muted-foreground'>VS Last Top</p>
          <p className={`text-xs font-semibold ${
            result.cycleChange !== null
              ? result.cycleChange >= 0 ? 'text-emerald-600' : 'text-red-600'
              : ''
          }`}>
            {result.coin.category === 'veteran' ? formatPct(result.cycleChange) : '—'}
          </p>
        </div>
        <div className='rounded-lg border p-2 bg-background/60'>
          <p className='text-[10px] text-muted-foreground'>Above 5yr Low</p>
          <p className={`text-xs font-semibold ${
            result.aboveFiveYearLow !== null
              ? result.aboveFiveYearLow > 25 ? 'text-emerald-600' : 'text-red-600'
              : ''
          }`}>
            {formatPct(result.aboveFiveYearLow)}
          </p>
        </div>
      </div>

      <p className='text-xs text-muted-foreground leading-relaxed'>{result.observation}</p>
    </div>
  );
}

